@router.get("/all")
def get_transactions():
    return TRANSACTIONS

@router.get("/classify")
def classify_transaction(description: str):
    if "payment" in description.lower() or "received" in description.lower():
        return {"category": "Revenue"}
    return {"category": "Miscellaneous"}
